import{_ as e,o as a,c as i,a2 as t}from"./chunks/framework.b3aQeZRM.js";const u=JSON.parse('{"title":"Agents and Client Compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"agents.md","filePath":"agents.md"}'),n={name:"agents.md"};function l(o,s,p,r,h,c){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="agents-and-client-compatibility" tabindex="-1">Agents and Client Compatibility <a class="header-anchor" href="#agents-and-client-compatibility" aria-label="Permalink to &quot;Agents and Client Compatibility&quot;">​</a></h1><p>Relay is designed for local-agent workflows where tools expect hosted API shapes.</p><h2 id="quick-connect" tabindex="-1">Quick Connect <a class="header-anchor" href="#quick-connect" aria-label="Permalink to &quot;Quick Connect&quot;">​</a></h2><p>After setup, point any OpenAI/Anthropic-compatible agent at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Base URL: http://127.0.0.1:1234/v1</span></span>
<span class="line"><span>API Key:  (leave blank unless API_KEY is set in .env)</span></span>
<span class="line"><span>Model:    any model from /v1/models</span></span></code></pre></div><h2 id="tested-clients" tabindex="-1">Tested Clients <a class="header-anchor" href="#tested-clients" aria-label="Permalink to &quot;Tested Clients&quot;">​</a></h2><p>Relay works with any client that allows custom base URLs and model IDs:</p><ul><li><strong>opencode</strong> — set <code>provider.base_url</code> to <code>http://127.0.0.1:1234/v1</code></li><li><strong>Cursor</strong> — add as custom OpenAI-compatible provider</li><li><strong>Claude Code</strong> — use <code>ANTHROPIC_BASE_URL=http://127.0.0.1:1234/v1</code></li><li><strong>Continue</strong> — add as OpenAI-compatible provider in config</li><li><strong>Aider</strong> — <code>--openai-api-base http://127.0.0.1:1234/v1</code></li></ul><h2 id="session-affinity" tabindex="-1">Session Affinity <a class="header-anchor" href="#session-affinity" aria-label="Permalink to &quot;Session Affinity&quot;">​</a></h2><p>For multi-project setups, use the <code>session-id</code> header to keep conversations isolated:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Project A</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;session-id: project-alpha&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:1234/v1/chat/completions</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Project B — Relay restarts the model to clear context</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;session-id: project-beta&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:1234/v1/chat/completions</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span></span></code></pre></div><h2 id="public-sharing" tabindex="-1">Public Sharing <a class="header-anchor" href="#public-sharing" aria-label="Permalink to &quot;Public Sharing&quot;">​</a></h2><p>See <a href="./deploy-public">Public Deployment</a> to share your relay with friends over HTTPS.</p><h2 id="known-limits" tabindex="-1">Known Limits <a class="header-anchor" href="#known-limits" aria-label="Permalink to &quot;Known Limits&quot;">​</a></h2><ul><li>Relay does not implement hosted platform orchestration (assistants, threads, runs)</li><li>Non-function tools (web search, code interpreter) are stripped</li><li>See <a href="./api-compatibility">API Compatibility</a> for full endpoint support</li></ul>`,15)])])}const k=e(n,[["render",l]]);export{u as __pageData,k as default};
